module.render:
const color = args.color || 'var(--accent-color)';
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const gap = (args.gap && String(args.gap).trim()) || '12px';
const compact = String(args.compact) === 'true';
const al = String(args.align || 'center').toLowerCase();
const align = al === 'left' ? 'left' : al === 'right' ? 'right' : 'center';
const cls = 'mdp-mod-kanban' + (compact ? ' mdp-kb-compact' : '');
const cols = sections.map((s) => (s || '').trim()).filter(Boolean);
let html = `\n\n<div class="${cls}" style="--kb-color:${color}; --kb-align:${align}; gap:${gap};">`;
cols.forEach((c) => {
  const lines = c.split('\n');
  const title = (lines.shift() || '').replace(/^#+\s*/, '').trim();
  const body = lines.join('\n').trim();
  html += `<div class="mdp-kb-col"><div class="mdp-kb-title">${esc(title)}</div><div class="mdp-kb-cards">\n\n${body}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
